INSERT OR REPLACE INTO App (id, slug, name, tagline, description, price, imageUrl, demoUrl, stripePriceId, featured, createdAt)
VALUES
  ('cm_slapmeter', 'slap-o-meter', 'Slap-O-Meter', 'Slap your phone. Get rated. Question your life choices.', 'Slap your phone as hard as you dare and our advanced advanced slap analysis engine will rate your slap from ''pathetic'' to ''LEGENDARY''. Features include leaderboards, slow-motion replay commentary, and a narrator who judges you harder than your parents ever did.', 499, '/images/slap-o-meter.png', NULL, '', 1, datetime('now')),
  ('cm_excusegen', 'excuse-generator', 'Excuse Generator', 'Shake for excuses. Never be accountable again.', 'Late to work? Forgot your anniversary? Didn''t do your homework? Just shake your phone and get an algorithmically generated excuse so absurd that people will be too confused to be mad. Comes with ''Boss Mode'', ''Partner Mode'', and ''Teacher Mode'' for situation-specific excuses.', 399, '/images/excuse-generator.png', '/play/excuse-generator', '', 1, datetime('now')),
  ('cm_roastselfie', 'roast-my-selfie', 'Roast My Selfie', 'Take a selfie. Get emotionally destroyed.', 'Upload a selfie and our brutally honest AI will roast you harder than a Thanksgiving turkey. Share your roast cards on social media for maximum humiliation. Features adjustable roast intensity from ''gentle tease'' to ''career-ending burn''.', 499, '/images/roast-my-selfie.png', NULL, '', 1, datetime('now')),
  ('cm_typingsounds', 'typing-sounds', 'Typing Sound Customizer', 'Every keypress makes a different sound. Farts, meows, gunshots, or moaning.', 'Turn your boring keyboard into a symphony of chaos. Pick from 5 sound packs — farts, cat meows, gun shots, classic typewriter, or moaning — and every key you press makes a different sound. The faster you type, the more dramatic it gets. Perfect for annoying coworkers, recording TikToks, or ruining Zoom calls.', 499, '/images/typing-sounds.png', '/play/typing-sounds', '', 1, datetime('now')),
  ('cm_chargegasm', 'chargegasm', 'ChargeGasm', 'Your laptop moans when you plug it in. Screams when you unplug.', 'Plug in your charger and your laptop moans with pleasure. Unplug it and it screams in agony. Choose from multiple sound effects, adjust volume, toggle looping, and preview sounds. Works system-wide — just plug or unplug your charger and hear the magic. Perfect for coffee shops, libraries, and anywhere you want maximum embarrassment.', 499, '/images/chargegasm.png', NULL, '', 1, datetime('now'));
